mapper.select:


    1 = 1

        and h.handover_no like concat('%', #{handoverNo}, '%')


        and h.asset_id = #{assetId}


        and h.handover_type = #{handoverType}


        and h.handover_status = #{handoverStatus}


        and h.from_dept_id = #{fromDeptId}


        and h.from_user_id = #{fromUserId}


        and h.to_dept_id = #{toDeptId}


        and h.to_user_id = #{toUserId}


        and date_format(h.handover_date, '%Y%m%d') >= date_format(#{params.beginTime}, '%Y%m%d')


        and date_format(h.handover_date, '%Y%m%d') <= date_format(#{params.endTime}, '%Y%m%d')


order by h.handover_date desc, h.handover_id desc
